"""
Represents the Checkers board.
"""

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Place pieces on the board
        piece_types = ['b', 'r']  # b for black, r for red
        starting_row = 0 if len(piece_types) == 2 else 1
        ending_row = 3 if len(piece_types) == 2 else 7

        for row in range(starting_row, ending_row):
            for col in range((row + starting_row) % 2, 8, 2):
                self.grid[row][col] = Piece(piece_types[0], (row, col))
                if row == 7 and piece_types[0] == 'r':
                    self.grid[row][col] = KingPiece(piece_types[0], (row, col))
        for row in range(ending_row + 1, 8 - starting_row):
            for col in range((row + ending_row) % 2, 8, 2):
                self.grid[row][col] = Piece(piece_types[1], (row, col))

    def display(self):
        # Print the board
        print("   ", end="")
        for i in range(8):
            print(f" {i} ", end="")
        print()
        for row in range(8):
            print(row, "|", end=" ")
            for col in range(8):
                if self.grid[row][col]:
                    print(self.grid[row][col], end=" |")
                else:
                    print("   ", end="|")
            print()

    def move_piece(self, start_pos, end_pos):
        # Move a piece from start_pos to end_pos
        piece = self.grid[start_pos[0]][start_pos[1]]
        if piece:
            self.grid[end_pos[0]][end_pos[1]] = piece
            self.grid[start_pos[0]][start_pos[1]] = None
            return True
        return False

    def is_valid_move(self, start_pos, end_pos):
        # Check if the move is valid
        piece = self.grid[start_pos[0]][start_pos[1]]
        if not piece:
            return False
        return piece.is_valid_move(start_pos, end_pos, self.grid)

```

#### Piece Class

