"""
Represents a Checker Piece.
"""

class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.king = False

    def is_king(self):
        return self.king

    def set_king(self):
        self.king = True

    def get_color(self):
        return self.color

    def move(self, end_pos):
        # Update the piece's position
        self.position = end_pos

    def is_valid_move(self, start_pos, end_pos, board):
        # Implement standard Checkers move rules
        delta_x = abs(end_pos[0] - start_pos[0])
        delta_y = abs(end_pos[1] - start_pos[1])

        if self.color == 'r':
            # Red pieces can only move up or capture diagonally down
            if end_pos[0] >= start_pos[0] or delta_x != 1 or delta_y != 1:
                return False
        else:
            # Black pieces can only move down or capture diagonally up
            if end_pos[0] <= start_pos[0] or delta_x != 1 or delta_y != 1:
                return False

        if board[end_pos[0]][end_pos[1]]:
            return False

        return True

class KingPiece(Piece):
    def is_valid_move(self, start_pos, end_pos, board):
        # Implement king's move rules
        delta_x = abs(end_pos[0] - start_pos[0])
        delta_y = abs(end_pos[1] - start_pos[1])

        if delta_x != 1 or delta_y != 1:
            return False

        if board[end_pos[0]][end_pos[1]]:
            return False

        return True
